+  if (tokenError) {
+    ctx.runtime.error(tokenError);
+    ctx.runtime.exit(1);
+    return null;
+  }
+
+  let expires: number | undefined;
+  const expiresInRaw = ctx.opts.tokenExpiresIn?.trim();
+  if (expiresInRaw) {
+    try {
+      expires = Date.now() + parseDurationMs(expiresInRaw, { defaultUnit: "d" });
