+    credential: {
+      type: "token",
+      provider: PROVIDER_ID,
+      token,
+      ...(expires ? { expires } : {}),
+    },
+  });
+  return applyAuthProfileConfig(ctx.config, {
+    profileId,
+    provider: PROVIDER_ID,
+    mode: "token",
+  });
+}
